import subprocess

def convert_image(event, context):
    filename = event['filename']
    options = event.get('options', '')
    
    # Construct the ImageMagick command
    command = ['convert', filename] + options.split()
    
    try:
        # Run the ImageMagick command
        subprocess.call(command)
        return {
            'statusCode': 200,
            'body': f'Image {filename} converted successfully.'
        }
    except Exception as e:
        return {
            'statusCode': 500,
            'body': f'Error converting image: {str(e)}'
        }